import type { ReactNode } from "react";
import { __ } from "@/i18n";
import {
  Card,
  CardAction,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Switch } from "@/components/ui/switch";
import { useWidgetStore } from "@/stores/widget-store";
import { WidgetPublish } from "@/components/widget-publish";
import { DEFAULT_WIDGET_CONFIG } from "@/constants/widget-config";
import { FontSizeIcon } from "@/icons/font-size";
import { HighlightTitleIcon } from "@/icons/highlight-title";
import { HighlightLinksIcon } from "@/icons/highlight-links";
import { DyslexiaFontIcon } from "@/icons/dyslexia-font";
import { FontWeightIcon } from "@/icons/font-weight";
import { LetterSpacingIcon } from "@/icons/letter-spacing";
import { LineHeightIcon } from "@/icons/line-height";
import { TextAlignIcon } from "@/icons/text-align";
import { DarkContrastIcon } from "@/icons/dark-contrast";
import { LightContrastIcon } from "@/icons/light-contrast";
import { HighContrastIcon } from "@/icons/high-contrast";
import { HighSaturationIcon } from "@/icons/high-saturation";
import { LowSaturationIcon } from "@/icons/low-saturation";
import { MonochromeIcon } from "@/icons/monochrome";
import { BigCursorIcon } from "@/icons/big-cursor";
import { StopAnimationsIcon } from "@/icons/stop-animations";
