interface ModuleRowProps {
  id: string;
  label: string;
  icon?: React.FC<React.SVGProps<SVGSVGElement>>;
  checked: boolean;
  onChange: (checked: boolean) => void;
}

function ModuleRow({ id, label, icon: Icon, checked, onChange }: ModuleRowProps) {
  return (
    <div className="cy:flex cy:items-center cy:justify-between cy:px-4 cy:py-5 cy:border-t">
      <div className="cy:flex cy:items-center cy:gap-3">
        {Icon ? (
          <Icon width={20} height={20} className="cy:text-gray-500 cy:shrink-0" />
        ) : null}
        <label
          htmlFor={id}
          className="cy:text-sm! cy:font-normal! cy:text-gray-800! cy:cursor-pointer"
        >
          {label}
        </label>
      </div>
      <Switch id={id} checked={checked} onCheckedChange={onChange} />
    </div>
  );
}

interface ModuleSectionProps {
  title: string;
  children: ReactNode;
}

/** Renders a labelled group of module toggles. Uses h3, intended to nest under the CardTitle h2. */
function ModuleSection({ title, children }: ModuleSectionProps) {
  return (
    <Card className="cy:rounded-lg cy:gap-0 cy:py-0 cy:shadow-none! cy:overflow-hidden">
      <div className="cy:bg-gray-50 cy:px-4 cy:py-3 cy:border-b">
        <h3 className="cy:text-sm cy:font-semibold cy:text-gray-900">{title}</h3>
      </div>
      <div>{children}</div>
    </Card>
  );
}

